import React from 'react';

const rooms = [
  {
    name: 'Garden Villa',
    type: 'Standard',
    
    img: 'https://images.unsplash.com/photo-1631049307264-da0ec9d70304?w=600&q=80',
    desc: 'A serene retreat nestled among tropical gardens with a private terrace.',
   
  },
  {
    name: 'Ocean Deluxe',
    type: 'Deluxe',
    price: '$480',
    img: 'https://images.unsplash.com/photo-1590073242678-70ee3fc28e8e?w=600&q=80',
    desc: 'Wake up to panoramic ocean views from your elegant suite with a plunge pool.',
    tags: ['Free WiFi', 'AC', 'Plunge Pool', 'Ocean View'],
  },
  {
    name: 'Overwater Suite',
    type: 'Suite',
    price: '$850',
    img: 'https://images.unsplash.com/photo-1602002418082-a4443e081dd1?w=600&q=80',
    desc: 'A glass-floor suite suspended above crystal-clear lagoon waters.',
    tags: ['Free WiFi', 'AC', 'Private Pool', 'Butler Service'],
  },
  {
    name: 'Family Bungalow',
    type: 'Family',
    price: '$560',
    img: 'https://images.unsplash.com/photo-1596394516093-501ba68a0ba6?w=600&q=80',
    desc: 'Spacious beachfront bungalow with separate areas, perfect for families.',
    tags: ['Free WiFi', 'AC', 'Pool Access', 'Kids Club'],
  },
];

const scrollTo = (id) => document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });

function Rooms() {
  return (
    <div id="rooms" className="rooms-bg">
      <div className="rooms-inner">
        <p className="section-tag">Accommodations</p>
        

        <div className="rooms-grid">
          {rooms.map((r) => (
            <div className="room-card" key={r.name}>
              <img src={r.img} alt={r.name} loading="lazy" />
              <div className="room-body">
                <p className="room-type">{r.type}</p>
                <h3>{r.name}</h3>
                <p>{r.desc}</p>
                <div className="room-tags">
                  {r.tags.map((t) => <span key={t}>{t}</span>)}
                </div>
                <div className="room-footer">
                  
                  <button className="btn-gold" onClick={() => scrollTo('contact')}>Book</button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default Rooms;
